import React, { useState, useEffect, useRef } from "react";
import "../styles/GeneralChat.css";
import { getTherapistReply } from "../data/therapistResponses";

const GeneralChat = () => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [typing, setTyping] = useState(false);
  const chatEndRef = useRef(null);

  /* Auto-scroll */
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, typing]);

  /* Initial Bot Message */
  useEffect(() => {
    setMessages([
      {
        sender: "bot",
        text: "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?",
      },
    ]);
  }, []);

  /* Detect mood from text */
  const detectMood = (text) => {
    const lower = text.toLowerCase();

    if (lower.includes("angry") || lower.includes("mad")) return "anger";
    if (lower.includes("sad") || lower.includes("lonely") || lower.includes("depressed")) return "sadness";
    if (lower.includes("anxious") || lower.includes("stress") || lower.includes("worried")) return "anxiety";
    if (lower.includes("happy") || lower.includes("good") || lower.includes("great")) return "happiness";

    return "neutral";
  };

  /* Save mood history */
  const saveMood = (mood) => {
    const history = JSON.parse(localStorage.getItem("moodHistory")) || [];

    history.push({
      mood,
      time: Date.now(),
      intensity: Math.floor(Math.random() * 4) + 2, // realistic range 2–5
    });

    localStorage.setItem("moodHistory", JSON.stringify(history));
  };

  /* Send Message */
  const sendMessage = () => {
    if (!input.trim()) return;

    const userMessage = {
      sender: "user",
      text: input,
    };

    setMessages((prev) => [...prev, userMessage]);
    setInput("");

    const mood = detectMood(input);
    saveMood(mood);

    setTyping(true);

    setTimeout(() => {
      const botReply = {
        sender: "bot",
        text: getTherapistReply(mood),
      };

      setTyping(false);
      setMessages((prev) => [...prev, botReply]);
    }, 1200);
  };

  return (
    <div className="chat-container">
      {/* HEADER */}
      <div className="chat-header">
        <h2>🧠 General Chat</h2>
        <p>❤️ Listening</p>
      </div>

      {/* CHAT BODY */}
      <div id="chat-body">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message ${msg.sender === "user" ? "user-msg" : "bot-msg"}`}
          >
            <div className="message-bubble">{msg.text}</div>
          </div>
        ))}

        {/* Typing Indicator */}
        {typing && (
          <div className="typing-indicator">
            <span className="dot"></span>
            <span className="dot"></span>
            <span className="dot"></span>
          </div>
        )}

        <div ref={chatEndRef}></div>
      </div>

      {/* INPUT */}
      <div className="chat-input">
        <input
          type="text"
          placeholder="Type how you feel..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && sendMessage()}
        />
        <button onClick={sendMessage}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
